import * as React from 'react';

interface IInputNumberState {
    value: string
    offValue: string
}

interface IInputNumberProps {
    value: number;
    onChange: Function;
    onAdd?: Function;
    fixed?: number;
    continuous?: boolean;
    continuousStartCallback?: Function;
    continuousEndCallback?: Function;
    width?: number;
    step?: number;
    max?: number;
    min?: number;
    multMode?: boolean;
    onBlur?: Function;
    onFocus?: Function;
    dropReverse?: boolean;
    disable?: boolean;
    lock?: boolean;
}

export default class InputNumber extends React.Component<IInputNumberProps, IInputNumberState> {

    public static defaultMax: number = Number.MAX_VALUE;
    public static defaultMin: number = -Number.MAX_VALUE;
    public static MULT_DEFAULT_TEXT: string = '--';

    protected _invalid: boolean = false;
    protected _downValue: number = 0;
    protected _downX: number = 0;
    protected _over: boolean = false;
    protected _isMouseMoved: boolean = false;
    protected _isMouseDown: boolean = false;
    protected _isFocus: boolean = false;
    protected _input: HTMLInputElement | null = null;

    constructor(props: IInputNumberProps, context: any) {
        super(props, context);
    }

    public get realValue(): number {
        return this.getValueFromProp(this.props);
    }

    protected get continuous(): boolean {
        return this.props.continuous === undefined ? true : !!this.props.continuous;
    }

    protected get maxValue(): number {
        let max: number = this.props.max as number;
        if (isNaN(max)) {
            return InputNumber.defaultMax;
        }
        return max;
    }

    protected get minValue(): number {
        let min: number = this.props.min as number;
        if (isNaN(min)) {
            return InputNumber.defaultMin;
        }
        return min;
    }

    protected get step(): number {
        let s: number = this.props.step as number;
        if (isNaN(s)) {
            return 1;
        }
        return s;
    }

    protected getValueFromProp(prop: IInputNumberProps): number {
        return this.getFixNumber(prop.value, prop.fixed as number);
    }

    protected getFixNumber(v: number, p: number): number {
        if (isNaN(p)) {
            p = 0;
        }
        let b: number = Math.pow(10, p);
        if (isNaN(v)) {
            v = 0;
        }
        return Math.round(v * b) / b;
    }

    protected getRenderValue(v: string): number {
        let n: number = parseFloat(v);
        return this.getFixNumber(n, this.props.fixed as number);
    }

    protected isLimit(value: number): boolean {
        if (this.props.min != null && !isNaN(this.props.min)) {
            if (value < this.props.min) {
                return true;
            }
        }
        if (this.props.max != null && !isNaN(this.props.max)) {
            if (value > this.props.max) {
                return true;
            }
        }
        return false;
    }

    protected filterText(text: string, isInt: boolean): {value: number, halfValue: string} {
        if (this.props.multMode && text === InputNumber.MULT_DEFAULT_TEXT) {
            return {value: NaN, halfValue: text};
        }
        if (isInt) {
            let intReg: RegExp = new RegExp('[-]?[0-9]*');
            let intMatch = text.match(intReg);
            if (intMatch != null) {
                let halfValue = intMatch[0];
                let v = NaN;
                if (halfValue == '-' || halfValue == '') {
                    v = NaN;
                } else {
                    v = this.getRenderValue(halfValue);
                }
                return {value: v, halfValue: halfValue};
            }
        } else {
            let floatReg: RegExp = new RegExp('[-]?[0-9]+[.]?[0-9]*');
            let floatMatch = text.match(floatReg);
            if (floatMatch != null) {
                let halfValue = floatMatch[0];
                let v = NaN;
                if (halfValue == '-' || halfValue[halfValue.length - 1] == '.' || halfValue == '') {
                    v = NaN;
                } else {
                    v = this.getRenderValue(halfValue);
                }
                return {value: v, halfValue: halfValue};
            } else {
                if (text == '-' || text == '') {
                    return {value: NaN, halfValue: text};
                }
            }
        }
        return {value: 0, halfValue: '0'};
    }

    protected addValue = (v: number): void => {
        if (isNaN(v)) {
            return;
        }
        if (this.props.onAdd) {
            this.props.onAdd(v);
        }
    }

    protected changeValue = (v: number, changeData: boolean = true): void => {
        if (isNaN(v)) {
            return;
        }
        if (v < this.minValue) {
            v = this.minValue;
        }

        if (v > this.maxValue) {
            v = this.maxValue;
        }

        if (this.props.value != v) {
            this.setState({value: v.toString()});
            if (changeData) {
                if (this.props.onChange) {
                    this.props.onChange(v);
                }
            }
        }
    }

    onMouseOver = (e: any): void => {
        this._over = true;
        if (this._input) {
            this._input.addEventListener('mousewheel', this.onMouseWheel);
        }
    }

    onMouseOut = (e: any): void => {
        this._over = false;
        if (this._input) {
            this._input.removeEventListener('mousewheel', this.onMouseWheel);
        }
    }

    onMouseDown = (e: any): void => {
        if (this._isFocus) {
            return;
        }
        if (this.props.lock) {
            return;
        }
        if (this.continuous) {
            if (this.props.continuousStartCallback) {
                this.props.continuousStartCallback();
            }
        }
        this._downX = 0;
        this._isMouseDown = true;
        this._isMouseMoved = false;
        document.addEventListener('mousemove', this.onMouseMove);
        document.addEventListener('mouseup', this.onMouseUp);
    }

    onMouseUp = (e: any): void => {
        let readyFocus: boolean = false;
        if (!this._isMouseMoved && this._isMouseDown) {
            readyFocus = true;
        }
        this._isMouseDown = false;
        this._isMouseMoved = false;
        if (this.props.multMode) {
            this.setState({offValue: ''});
        }
        document.removeEventListener('mousemove', this.onMouseMove);
        document.removeEventListener('mouseup', this.onMouseUp);

        if (this.continuous) {
            if (this.props.continuousEndCallback) {
                this.props.continuousEndCallback();
            }
        }
        if (readyFocus && this._input) {
            this._input.focus();
            this._input.select();
        }
    }

    onMouseMove = (e: any): void => {
        if (this._downX == 0) {
            this._downX = e.clientY;
            this._downValue = this.getRenderValue(this.state.value);
        } else {
            this._isMouseMoved = true;
            let off: number = e.clientY - this._downX;
            if (this.props.dropReverse) {
                off = -off;
            }
            off *= this.step;
            if (off != 0) {
                if (this.props.multMode) {
                    this.addValue(off);
                    let offValue = '';
                    if (off > 0) {
                        offValue = '+' + off;
                    } else if (off < 0) {
                        offValue = off.toString();
                    }
                    this.setState({offValue: offValue});
                } else {
                    this.changeValue(this._downValue + off, this.continuous);
                }
            }
        }
    }

    onMouseWheel = (e: any): void => {
        let delta: number = e.wheelDelta;
        if (delta > 0) {
            this.changeValue(this.props.value + this.step);
        } else {
            this.changeValue(this.props.value - this.step);
        }
    }

    onDrag = (e: any): void => {
        document.removeEventListener('mousemove', this.onMouseMove);
        document.removeEventListener('mouseup', this.onMouseUp);
        e.preventDefault();
    }

    onChange = (e: any): void => {
        if (this.props.lock) {
            return;
        }
        let textValue: string = e.target.value;
        let isFloat: boolean = (this.props && this.props.fixed && this.props.fixed > 0) ? true : false;
        let filterText = this.filterText(textValue, !isFloat);
        if (isNaN(filterText.value) || this.isLimit(filterText.value)) {
            // 中间状态实际值不变
            this.setState({value: filterText.halfValue});
        } else {
            // 实际值发生了改变
            let v: number = filterText.value;
            this.changeValue(v);
        }
    }

    onBlur = (e: any): void => {
        this._isFocus = false;
        this.setState({});
        if (this._isMouseDown) {
            return;
        }
        let isFloat: boolean = (this.props && this.props.fixed && this.props.fixed > 0) ? true : false;
        let v = this.filterText(e.target.value, !isFloat);
        if (isNaN(v.value) || this.isLimit(v.value)) {
            this.setState({value: this.props.value.toString()});
        }
        document.removeEventListener('mousemove', this.onMouseMove);
        document.removeEventListener('mouseup', this.onMouseUp);
        if (this.props.onBlur) {
            this.props.onBlur();
        }
    }

    onFocus = (e: any): void => {
        if (this._isMouseDown) {
            if (this._input) this._input.blur();
        } else {
            if (this.props.multMode) {
                if (this._input) this._input.select();
            }
            if (this.props.onFocus) {
                this.props.onFocus();
            }
            this._isFocus = true;
            this.setState({});
        }
    }

    componentWillMount() {
        this.setState({value: this.realValue.toString()});
    }

    componentWillReceiveProps(newProp: IInputNumberProps) {
        let newValue: string = this.getValueFromProp(newProp).toString();
        if (this.state.value != newValue) {
            this._invalid = true;
            this.setState({value: newValue});
        }
    }

    render() {
        this._invalid = false;
        let w: string = this.props.width ? this.props.width  + 'px' : '100%';
        let displayValue: string = this.state.value;
        if (this.props.multMode) {
            displayValue = InputNumber.MULT_DEFAULT_TEXT;
            if (this.state.offValue != null && this.state.offValue != '') {
                displayValue = this.state.offValue;
            }
        }
        let disable = this.props.disable;
        let cursor = this._isFocus ? 'text' : 'n-resize';
        let cName = 'inputNumber';
        if (disable) {
            cName = 'inputNumber disabled';
        }
        return(
            <input
                className={cName}
                style={{
                    width: w,
                    cursor: cursor
                }}
                disabled={disable}
                step={this.props.step || 1}
                value={displayValue}
                onChange={this.onChange}
                onMouseDown={this.onMouseDown}
                onMouseOver={this.onMouseOver}
                onMouseOut={this.onMouseOut}
                onDrag={this.onDrag}
                onBlur={this.onBlur}
                onFocus={this.onFocus}
                ref={(input) => this._input = input}
            />
        );
    }
}