import * as React from "react";
import { RouteComponentProps, withRouter } from "react-router";
import { connect } from "react-redux";
import { IUserInfo } from "../interfaces/IAccount";
import { Dropdown, Avatar, Button, Menu, message } from "antd";
import { formatMessage } from "../AppRouter";
import { ISite } from "../interfaces/ISetting";
import { signOut, getRepoContents, createOrUpdateFileContents } from "../actions/githubActions";
import { IBlogNav } from "../interfaces/IBlog";

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    userInfo: IUserInfo;
    siteInfo: ISite;
    blogNavTreeData: IBlogNav[];
    signOut: Function;
    getRepoContents: Function;
    createOrUpdateFileContents: Function;
}

const mapStateToProps = (state: any) => {
    return {
        blogNavTreeData: state.blog.navTreeData,
        userInfo: state.account.userInfo,
        siteInfo: state.setting.siteInfo
    }
};

const mapDispatchTpProps = {
    signOut,
    getRepoContents,
    createOrUpdateFileContents
};


class UserToolbar extends React.Component<IProps, IState> {


    onUserMenuClick = (e: any) => {
        let action: string = e.item.props['data-action'];
        if (action) {
            switch (action) {
                case 'signIn':
                    if (this.props.siteInfo.appClientID) {
                        const win = window as any;
                        win.location.href = `https://github.com/login/oauth/authorize?client_id=` + this.props.siteInfo.appClientID;
                    } else {
                        this.props.history.push(`${process.env.PUBLIC_URL}/login`)
                    }
                    break;
                case 'signOut':
                    this.props.signOut();
                    break;
                case 'generateSitemap':
                    this.generateSitemap();
                    break;
            }
        }
    };

    generateSitemap = () => {
        const sitemapPath = 'sitemap.xml';
        const ref = 'master';
        this.props.getRepoContents(
            this.props.siteInfo.repo,
            sitemapPath,
            ref,
            (res: any) => {
                if (res) {
                    const win = window as any;
                    const zanejs = win.zanejs;
                    const rootUrl = win.location.protocol + "//" + win.location.host + "/#/article/"
                    let sitemapXml = `<?xml version="1.0" encoding="UTF-8"?>\n`;
                    sitemapXml += `<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n`;
                    const loop = ($data: any) => $data.map((item: any, index: number) => {
                        if (item.path && !zanejs.utils.isAbsoluteUrl(item.path)) {
                            sitemapXml += ` <url>\n`;
                            sitemapXml += `     <loc>${rootUrl + encodeURIComponent(item.path)}</loc>\n`;
                            sitemapXml += `     <lastmod>${(new Date()).toLocaleDateString().replace(/\//g, "-")}</lastmod>\n`;
                            sitemapXml += `     <changefreq>always</changefreq>\n`;
                            sitemapXml += `     <priority>1.0</priority>\n`;
                            sitemapXml += ` </url>\n`;
                        }
                        if (item.children) {
                            loop(item.children);
                        }
                    });
                    loop(this.props.blogNavTreeData);
                    sitemapXml += `</urlset>`;

                    const configDataToStr = unescape(sitemapXml);
                    const configDataBase64Str = win.btoa(configDataToStr);
                    this.props.createOrUpdateFileContents(
                        this.props.siteInfo.repo, 
                        sitemapPath, 
                        configDataBase64Str, 
                        res.sha, 
                        ref, 
                        (res: any) => {
                            if (res && res.content && res.content.sha) {
                                message.success(formatMessage({id: "app.saveSuccess"}));
                            } else {
                                message.success(formatMessage({id: "app.saveFail"}));
                            }
                        }
                    );
                }
            },
            (res: any) => {
                message.error(formatMessage({id: 'app.page404Title'}));
            }
        );
    };

    render() {
        let userMenu = null;
        if (this.props.userInfo) {
            userMenu = (
                <Menu
                    className="editor-drop-menu user-menu"
                    onClick={this.onUserMenuClick}>
                    <Menu.Item key="nickname" data-action="#">
                        <div className="icon">
                            <span className="iconfont">&#xe60e;</span>
                        </div>
                        <div className="text">{this.props.userInfo.nickname}</div>
                    </Menu.Item>
                    <Menu.Item key="generateSitemap" data-action="generateSitemap">
                        <div className="icon">
                            <span className="iconfont">&#xe610;</span>
                        </div>
                        <div className="text">{formatMessage({id: 'app.generateSitemap'})}</div>
                    </Menu.Item>
                    <Menu.Item key="signOut" data-action="signOut">
                        <div className="icon">
                            <span className="iconfont">&#xe609;</span>
                        </div>
                        <div className="text">{formatMessage({id: 'app.signOut'})}</div>
                    </Menu.Item>
                </Menu>
            );
        } else {
            userMenu = (
                <Menu
                    className="editor-drop-menu user-menu"
                    onClick={this.onUserMenuClick}>
                    <Menu.Item key={1} data-action="signIn">
                        <div className="icon">
                            <span className="iconfont">&#xe60a;</span>
                        </div>
                        <div className="text">{formatMessage({id: 'app.signIn'})}</div>
                    </Menu.Item>
                </Menu>
            );
        }

        return (
            <div className="groupPanel">
                <div className="item">
                    {
                        this.props.userInfo 
                        ? (
                            <Avatar size="small" src={this.props.userInfo.avatarUrl} />
                        ) 
                        : (
                            <Avatar size="small" icon="user" />
                        )
                    }
                </div>
                <div className="item">
                    <Dropdown
                        overlay={userMenu}
                        trigger={['click']}>
                        <Button style={{width: 24, padding: 0, borderRadius: 12}}>
                            <span className="iconfont">&#xe608;</span>
                        </Button>
                    </Dropdown>
                </div>
            </div>
        )
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(UserToolbar));