import * as React from "react";
import { RouteComponentProps, withRouter } from "react-router";
import { connect } from "react-redux";
import { Tooltip, Tree, Icon, Input, message, Modal } from 'antd';
import { CSSProperties } from "react";
import { formatMessage } from "../../AppRouter";
import { updateMaxWidget, updateWidget, updateActivePanel } from "../../actions/settingActions";
import { getBlogNavData, updateBlogNavTreeConfig, updateBlogSha } from "../../actions/blogActions";
import { openFile, updateFile } from "../../actions/editorActions";
import { createOrUpdateFileContents, deleteGithubFile } from "../../actions/githubActions";
import { WidgetPos_Left, WidgetPos_NONE, WidgetPos_Right } from "../../constants/WidgetPos";
import { Editor_Panel_NavPanel } from "../../constants/EditorPanelNames";
import { ISite } from './../../interfaces/ISetting';
import { IBlogNav } from './../../interfaces/IBlog';
import { IUserInfo } from "../../interfaces/IAccount";
import { IPanes } from "../../interfaces/IPane";
import { IOpenFiles } from "../../interfaces/IOpenfile";
import { CONFIG_BLOG_URL } from './../../constants/Github';
import { WidgetName_Property_Explorer } from "../../constants/WidgetNames";
import { ADD_NAV_TREE_NODE_TYPE_FILE, ADD_NAV_TREE_NODE_TYPE_FOLDER } from "../../constants/AddNavTreeNodeType";
import { getTreeParentKey } from "../../utils/getTreeParentKey";
import { generateTreeDataToConfigData } from "../../utils/generateTreeDataToConfigData";

const { Search } = Input;
const { TreeNode } = Tree;

interface IState {
    
}

interface IProps extends RouteComponentProps<any> {
    blogNavTreeData: IBlogNav[];
    blogSha: string|null;
    navExpandedKeys: string[];
    navSelectedKey: string;
    navAutoExpandParent: boolean;
    navEditNodeTitle: string;
    addNavTreeNodeType: string;
    searchValue: string;
    leftWidget: string|null;
    rightWidget: string|null;
    maxWidget: number;
    activePanel: string|null|undefined;
    activePane: string|undefined;
    panes: IPanes;
    openfiles: IOpenFiles;
    userInfo: IUserInfo;
    siteInfo: ISite;
    updateWidget: Function;
    updateMaxWidget: Function;
    updateActivePanel: Function;
    getBlogNavData: Function;
    updateBlogNavTreeConfig: Function;
    updateBlogSha: Function;
    openFile: Function;
    updateFile: Function;
    createOrUpdateFileContents: Function;
    deleteGithubFile: Function;
}

const mapStateToProps = (state: any) => {
    return {
        siteInfo: state.setting.siteInfo,
        userInfo: state.account.userInfo,
        blogNavTreeData: state.blog.navTreeData,
        blogSha: state.blog.sha,
        navSelectedKey: state.blog.navSelectedKey,
        navExpandedKeys: state.blog.navExpandedKeys,
        navAutoExpandParent: state.blog.navAutoExpandParent,
        navEditNodeTitle: state.blog.navEditNodeTitle,
        addNavTreeNodeType: state.blog.addNavTreeNodeType,
        searchValue: state.blog.searchValue,
        leftWidget: state.setting.leftWidget,
        rightWidget: state.setting.rightWidget,
        maxWidget: state.setting.maxWidget,
        activePanel: state.setting.activePanel,
        activePane: state.editor.activePane,
        panes: state.panes,
        openfiles: state.openfiles
    }
};

const mapDispatchTpProps = {
    updateWidget,
    updateMaxWidget,
    updateActivePanel,
    getBlogNavData,
    openFile,
    updateFile,
    updateBlogNavTreeConfig,
    updateBlogSha,
    createOrUpdateFileContents,
    deleteGithubFile
};

const baseCSSProperties: CSSProperties = {
    position: 'absolute',
    overflow: 'hidden',
    left: 0,
    top: 0,
    right: 0,
    bottom: 0
};

/**
 *
 */
class BlogNavPanel extends React.Component<IProps, IState> {

    constructor(props: IProps) {
        super(props);
    }

    componentDidMount(): void {
        this.props.getBlogNavData();
        this.handleExpand([]);
    }

    handleMaxinize = () => {
        if (this.props.maxWidget !== WidgetPos_Left) {
            this.props.updateMaxWidget(WidgetPos_Left);
        } else {
            this.props.updateMaxWidget(WidgetPos_NONE);
        }
    };

    handleHide = () => {
        this.props.updateWidget(null, WidgetPos_Left);
        this.props.updateMaxWidget(WidgetPos_NONE);
    };

    handleSelect = (selectedKeys: string[], info: any) => {
        const nodeProps = info.node.props;
        this.props.updateBlogNavTreeConfig({
            navSelectedKey: nodeProps.eventKey
        });

        if (nodeProps.dataRef.children && nodeProps.dataRef.children.length > 0) {

        } else if (nodeProps.dataRef.path) {
            this.props.openFile({
                title: nodeProps.dataRef.title, 
                path: nodeProps.dataRef.path,
                editable: true
            });
        }
    };

    handleRightClick = () => {

    };

    handleDrop = (info: any) => {
        const dropKey = info.node.props.eventKey;
        const dragKey = info.dragNode.props.eventKey;
        const dropPos = info.node.props.pos.split('-');
        const dropPosition = info.dropPosition - Number(dropPos[dropPos.length - 1]);

        const loop = (data: any[], key: string, callback: Function) => {
            data.forEach((item: any, index: number, arr: any[]) => {
                if (item.key === key) {
                    return callback(item, index, arr);
                }
                if (item.children) {
                    return loop(item.children, key, callback);
                }
            });
        };

        const data = [...this.props.blogNavTreeData];

        // Find dragObject
        let dragObj: any;
        loop(data, dragKey, (item: any, index: number, arr: any[]) => {
            arr.splice(index, 1);
            dragObj = item;
        });

        if (!info.dropToGap) {
            // Drop on the content
            loop(data, dropKey, (item: any) => {
                item.children = item.children || [];
                // where to insert 示例添加到尾部，可以是随意位置
                item.children.push(dragObj);
            });
        } else if (
            (info.node.props.children || []).length > 0 && // Has children
            info.node.props.expanded && // Is expanded
            dropPosition === 1 // On the bottom gap
            ) {
                loop(data, dropKey, (item: any) => {
                    item.children = item.children || [];
                    // where to insert 示例添加到头部，可以是随意位置
                    item.children.unshift(dragObj);
                });
        } else {
            let ar: any = null;
            let i: number = 0;
            loop(data, dropKey, (item: any, index: number, arr: any[]) => {
                ar = arr;
                i = index;
            });
            if (ar) {
                if (dropPosition === -1) {
                    ar.splice(i, 0, dragObj);
                } else {
                    ar.splice(i + 1, 0, dragObj);
                }
            }
        }

        this.props.updateBlogNavTreeConfig({
            navTreeData: data
        });
    };

    handleNewFolder = () => {
        const data = [...this.props.blogNavTreeData];
        let index = 0;
        data.map(item => {
            if (item.key) {
                const arr = item.key.split("-");
                index = Math.max(index, parseInt(arr[arr.length - 1]));
            }
        });
        data.push({
            closeIcon: `${process.env.PUBLIC_URL}/assets/svg/folder-public.svg`,
            openIcon: `${process.env.PUBLIC_URL}/assets/svg/folder-public-open.svg`,
            icon: this.generateTreeItemIcon,
            key: `key-${index + 1}`,
            isEditable: true,
            children: []
        });
        
        this.props.updateBlogNavTreeConfig({
            navTreeData: data,
            navEditNodeTitle: '',
            addNavTreeNodeType: ADD_NAV_TREE_NODE_TYPE_FOLDER
        });
    };

    handleNewFile = () => {
        const data = [...this.props.blogNavTreeData];
        const expandedKeys = [...this.props.navExpandedKeys];
        let key = getTreeParentKey(this.props.navSelectedKey, data);
        key = key || this.props.navSelectedKey;
        if (key) {
            data.map(item => {
                if (item.key == key) {
                    let cIndex = 0;
                    if (!item.children) {
                        item.children = [];
                    } else {
                        item.children.map((_item: any) => {
                            const arr = _item.key.split("-");
                            cIndex = Math.max(cIndex, arr[arr.length - 1]);
                        });
                    }
                    const nodeKey = `${item.key}-${cIndex + 1}`;
                    item.children.push({
                        icon: <img src={`${process.env.PUBLIC_URL}/assets/svg/document.svg`} style={{marginTop: -5}} />,
                        key: nodeKey,
                        isEditable: true
                    });
                    expandedKeys.push(nodeKey);
                }
            });
        }
        
        this.props.updateBlogNavTreeConfig({
            navTreeData: data,
            navEditNodeTitle: '',
            navAutoExpandParent: true,
            navExpandedKeys: expandedKeys,
            addNavTreeNodeType: ADD_NAV_TREE_NODE_TYPE_FILE
        });
    };

    handleDelete = () => {
        if (this.props.navSelectedKey) {
            Modal.confirm({
                title: formatMessage({id: "app.deleteConfirmTitle"}),
                content: formatMessage({id: "app.deleteConfirmContent"}),
                okText: formatMessage({id: "app.ok"}),
                cancelText: formatMessage({id: "app.cancel"}),
                onOk: () => {
                    const deleteFiles: any[] = [];
                    const data = [...this.props.blogNavTreeData];
                    const findDeleteFiles = ($data: any) => $data.map((item: any, index: number, $arr: any) => {
                        if (item.path && item.sha) {
                            deleteFiles.push({
                                path: item.path,
                                sha: item.sha
                            })
                        }
                        if (item.children) {
                            findDeleteFiles(item.children);
                        }
                    });
                    const loop = ($data: any) => $data.map((item: any, index: number, $arr: any) => {
                        if (item.key == this.props.navSelectedKey) {
                            $arr.splice(index, 1);
                            if (item.path && item.sha) {
                                deleteFiles.push({
                                    path: item.path,
                                    sha: item.sha
                                })
                            }
                            if (item.children) {
                                findDeleteFiles(item.children);
                            }
                        } else if (item.children) {
                            loop(item.children);
                        }
                    });
                    loop(data);

                    this.updateBlogData(data, (res: boolean) => {
                        if (res) {
                            this.props.updateBlogNavTreeConfig({
                                navTreeData: data,
                                addNavTreeNodeType: ''
                            });
                        }
                    });

                    deleteFiles.map(deleteFile => {
                        this.props.deleteGithubFile(
                            this.props.siteInfo.repo,
                            deleteFile.path,
                            deleteFile.sha,
                            'master'
                        );
                    });
                }
            });
        }
    };

    handleEditFile = () => {
        const activePane = this.props.activePane ? this.props.panes[this.props.activePane] : null;
        if (activePane && activePane.activeFile) {
            const activeFile = this.props.openfiles[activePane.activeFile];
            if (activeFile && activeFile.editable) {
                activeFile.editing = !activeFile.editing;
                this.props.updateFile(activeFile);
                if (activeFile.editing) {
                    if (this.props.rightWidget != WidgetName_Property_Explorer) {
                        this.props.updateWidget(WidgetName_Property_Explorer, WidgetPos_Right);
                    }
                } else {
                    this.props.updateWidget(null, WidgetPos_Right);
                }
            }
        }
    };

    handleSearch = (e: any) => {
        const { value } = e.target;
        const dataList: any[] = [];
        const generateList = (data: any[]) => {
            for (let i = 0; i < data.length; i++) {
                const node = data[i];
                const { key, title } = node;
                dataList.push({ key, title });
                if (node.children) {
                    generateList(node.children);
                }
            }
        };
        generateList(this.props.blogNavTreeData);
        const expandedKeys = dataList.map((item: any) => {
            if (item.title.indexOf(value) > -1) {
                return getTreeParentKey(item.key, this.props.blogNavTreeData);
            }
            return null;
          })
          .filter((item: any, i: number, self: any) => item && self.indexOf(item) === i);
        
        this.props.updateBlogNavTreeConfig({
            navExpandedKeys: expandedKeys,
            searchValue: value,
            navAutoExpandParent: true
        });

    };

    handleExpand = (expandedKeys: string[]) => {
        this.props.updateBlogNavTreeConfig({
            navExpandedKeys: expandedKeys,
            navAutoExpandParent: false
        });
    };

    handleTreeNodeChange = (e: any) => {
        this.props.updateBlogNavTreeConfig({
            navEditNodeTitle: e.target.value
        });
    };

    handleTreeNodeClose = (key: string) => {
        const data = [...this.props.blogNavTreeData];
        const loop = ($data: any) => $data.map((item: any, index: number, $arr: any) => {
            if (item.key == key) {
                $arr.splice(index, 1);
            } else if (item.children) {
                loop(item.children);
            }
        });
        loop(data);
        this.props.updateBlogNavTreeConfig({
            navTreeData: data,
            addNavTreeNodeType: ''
        });
    };

    handleTreeNodeSave = (key: string) => {
        if (this.props.navEditNodeTitle) {
            let treeNode: any = null;
            const data = [...this.props.blogNavTreeData];
            const loop = ($data: any) => $data.map((item: any, index: number) => {
                if (item.key == key) {
                    treeNode = item;
                } else if (item.children) {
                    loop(item.children);
                }
            });
            loop(data);
            if (treeNode) {
                treeNode.title = this.props.navEditNodeTitle;
                treeNode.isEditable = false;
                treeNode.uploading = true;
                this.props.updateBlogNavTreeConfig({
                    navTreeData: data
                });
                
                if (this.props.addNavTreeNodeType == ADD_NAV_TREE_NODE_TYPE_FILE) {
                    treeNode.path = `md/${this.props.navEditNodeTitle}.md`;
                    this.props.createOrUpdateFileContents(
                        this.props.siteInfo.repo, 
                        treeNode.path, 
                        '', 
                        null, 
                        'master', 
                        (res: any) => {
                            if (res && res.content && res.content.sha) {
                                treeNode.uploading = false;
                                this.updateBlogData(data, (res1: boolean) => {
                                    if (res1) {
                                        this.props.updateBlogNavTreeConfig({
                                            navTreeData: data,
                                            addNavTreeNodeType: ''
                                        });
                                    } else {
                                        this.handleTreeNodeClose(key);
                                    }
                                });
                            } else {
                                this.handleTreeNodeClose(key);
                            }
                        }
                    );
                } else {
                    this.updateBlogData(data, (res: boolean) => {
                        if (res) {
                            treeNode.uploading = false;
                            this.props.updateBlogNavTreeConfig({
                                navTreeData: data,
                                addNavTreeNodeType: ''
                            });
                        } else {
                            this.handleTreeNodeClose(key);
                        }
                    });
                }
            }
        } else {
            message.error(formatMessage({id: 'app.newFolderNameEmpty'}));
        }
    };

    updateBlogData = (data: any, callback: Function|null = null) => {
        const win = window as any;
        const configData: any = generateTreeDataToConfigData(data);
        const configDataToStr = unescape(encodeURIComponent(JSON.stringify(configData)));
        const configDataBase64Str = win.btoa(configDataToStr);
        this.props.createOrUpdateFileContents(
            this.props.siteInfo.repo, 
            CONFIG_BLOG_URL, 
            configDataBase64Str, 
            this.props.blogSha, 
            'master', 
            (res: any) => {
                if (res && res.content && res.content.sha) {
                    this.props.updateBlogSha({
                        sha: res.content.sha
                    });
                    callback && callback(true);
                } else {
                    callback && callback(false);
                }
            }
        );
    };

    generateTreeItemIcon = (props: any) => {
        return <img src={props.expanded ? props.openIcon : props.closeIcon} style={{marginTop: -5}} />;
    };

    generateBloggerExplorer = () => {
        let editable = false;
        let editing = false;
        const loop = (data: any) => data.map((item: any) => {
            let title;
            if (item.isEditable) {
                title = (
                    <div style={{display: "inline"}}>
                        <input onChange={this.handleTreeNodeChange} style={{width: 160}} />
                        <Icon type='close' style={{ marginLeft: 10 }} onClick={(e) => {e.stopPropagation(); this.handleTreeNodeClose(item.key)}} />
                        <Icon type='check' style={{ marginLeft: 10 }} onClick={(e) => {e.stopPropagation(); this.handleTreeNodeSave(item.key)}} />
                    </div>
                );
            } else if (item.uploading) {
                title = (
                    <div style={{display: "inline"}}>
                        <Icon type="sync" spin />
                        <span>正在同步，请稍候...</span>
                    </div>
                );
            } else {
                const index = item.title.indexOf(this.props.searchValue);
                const beforeStr = item.title.substr(0, index);
                const afterStr = item.title.substr(index + this.props.searchValue.length);
                title = index > -1 ? (
                    <span>
                    {beforeStr}
                    <span style={{ color: '#f50' }}>{this.props.searchValue}</span>
                    {afterStr}
                    </span>
                ) : (
                    <span>{item.title}</span>
                );
            }
            if (item.children) {
                return (
                    <TreeNode key={item.key} {...item} title={title} dataRef={item}>
                        {loop(item.children)}
                    </TreeNode>
                );
            }
            return <TreeNode key={item.key} {...item} title={title} dataRef={item} />;
        });
        const activePane = this.props.activePane ? this.props.panes[this.props.activePane] : null;
        if (activePane && activePane.activeFile) {
            const activeFile = this.props.openfiles[activePane.activeFile];
            if (activeFile) {
                editable = !!activeFile.editable && !activeFile.err;
                editing = !!activeFile.editing;
            }
        }
        return (
            <div className="blogsExplorer">
                <div className="header">
                    <div className="toolbar">
                        <div style={{...baseCSSProperties, right: undefined, width: 2}} />
                        <div style={{...baseCSSProperties, right: undefined, left: 5, width: 200}}>
                            {formatMessage({id: 'app.blogsExplorer'})}
                        </div>
                        <div
                            onClick={this.handleMaxinize}
                            style={{
                                ...baseCSSProperties,
                                right: 2,
                                left: undefined,
                                width: 18
                            }}>
                            <Tooltip
                                placement="bottomLeft"
                                title={formatMessage({id: 'app.panelMaximize'})}>
                                <span className={'iconfont' + (this.props.maxWidget === WidgetPos_Left ? ' selected' : '')}>&#xe602;</span>
                            </Tooltip>
                        </div>
                        {
                            this.props.userInfo && (
                                <>
                                    <div 
                                        onClick={this.props.blogSha && this.props.addNavTreeNodeType == '' ? this.handleNewFolder : undefined}
                                        style={{
                                            ...baseCSSProperties,
                                            right: 20,
                                            left: undefined,
                                            width: 18
                                        }}>
                                        <Tooltip
                                            placement="bottomLeft"
                                            title={formatMessage({id: 'app.newFolder'})}>
                                            <span 
                                                className="iconfont"
                                                style={{
                                                    color: this.props.blogSha && this.props.addNavTreeNodeType == '' ? 'rgba(255, 255, 255, 0.4)' : 'rgba(255, 255, 255, 0.1)'
                                                }}>
                                                &#xe61c;
                                            </span>
                                        </Tooltip>
                                    </div>
                                    <div
                                        onClick={this.props.blogSha && this.props.navSelectedKey && this.props.addNavTreeNodeType == '' ? this.handleNewFile : undefined}
                                        style={{
                                            ...baseCSSProperties,
                                            right: 38,
                                            left: undefined,
                                            width: 18
                                        }}>
                                        <Tooltip
                                            placement="bottomLeft"
                                            title={formatMessage({id: 'app.newFile'})}>
                                            <span  
                                                className="iconfont"
                                                style={{
                                                    color: this.props.blogSha && this.props.navSelectedKey && this.props.addNavTreeNodeType == '' ? 'rgba(255, 255, 255, 0.4)' : 'rgba(255, 255, 255, 0.1)'
                                                }}>
                                                &#xe61a;
                                            </span>
                                        </Tooltip>
                                    </div>
                                    <div
                                        onClick={this.props.blogSha && this.props.navSelectedKey ?  this.handleDelete : undefined}
                                        style={{
                                            ...baseCSSProperties,
                                            right: 56,
                                            left: undefined,
                                            width: 18
                                        }}>
                                        <Tooltip
                                            placement="bottomLeft"
                                            title={formatMessage({id: 'app.delete'})}>
                                            <span  
                                                className="iconfont"
                                                style={{
                                                    color: this.props.blogSha && this.props.navSelectedKey ? 'rgba(255, 255, 255, 0.4)' : 'rgba(255, 255, 255, 0.1)'
                                                }}>
                                                &#xe620;
                                            </span>
                                        </Tooltip>
                                    </div>
                                    <div
                                        onClick={editable ? this.handleEditFile : undefined}
                                        style={{
                                            ...baseCSSProperties,
                                            right: 74,
                                            left: undefined,
                                            width: 18
                                        }}>
                                        <Tooltip
                                            placement="bottomLeft"
                                            title={formatMessage({id: 'app.editFile'})}>
                                            <span  
                                                className="iconfont"
                                                style={{
                                                    color: editing ? 'rgba(0, 184, 255, 1)' : editable ? 'rgba(255, 255, 255, 0.4)' : 'rgba(255, 255, 255, 0.1)'
                                                }}>
                                                &#xe61d;
                                            </span>
                                        </Tooltip>
                                    </div>
                                </>
                            )
                        }
                    </div>
                </div>
                <div className="body">
                    {
                        this.props.blogNavTreeData && this.props.blogNavTreeData.length > 0 
                        ? (
                            <>
                                <Search 
                                    style={{ padding: 8, marginTop: 5 }} 
                                    placeholder={formatMessage({id: 'app.search'})} 
                                    onChange={this.handleSearch} />
                                <Tree 
                                    showLine={true}
                                    showIcon={true}
                                    draggable={true}
                                    className="myTree"
                                    switcherIcon={<Icon type="down" />}
                                    onExpand={this.handleExpand}
                                    expandedKeys={this.props.navExpandedKeys}
                                    selectedKeys={[this.props.navSelectedKey]}
                                    autoExpandParent={this.props.navAutoExpandParent}
                                    onSelect={this.handleSelect}
                                    onRightClick={this.handleRightClick}
                                    onDrop={this.handleDrop}>
                                    {loop(this.props.blogNavTreeData)}
                                </Tree>
                            </>
                        ) 
                        : (
                            <p>暂无内容</p>
                        )
                    }
                </div>
            </div>
        );
    };

    render() {
        return (
            <div className="navPanel" onClick={() => this.props.updateActivePanel(Editor_Panel_NavPanel)}>
                <div 
                    className="content" 
                    style={{
                        zoom: 1,
                        /*backgroundColor: this.props.activePanel === Editor_Panel_NavPanel ? DEFAULT_ACTIVE_PANEL_COLOR : "transparent"*/
                    }}>
                    {this.generateBloggerExplorer()}
                </div>
            </div>
        )
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(BlogNavPanel));